  // 窗口管理
  getAppWindow(appName: string): Promise<WindowInfo>;
  activateApp(appName: string): Promise<void>;

  // UI 元素查找 (Accessibility API)
  findElement(appName: string, criteria: FindCriteria): Promise<ElementInfo[]>;

